function CoderAgent() {
  const [spec, setSpec] = React.useState('REPLACE_WITH_SPEC');
  const [language, setLanguage] = React.useState('python');
  const [code, setCode] = React.useState('');
  const [output, setOutput] = React.useState('');
  const [busy, setBusy] = React.useState(false);
  const draft = async () => {
    setBusy(true); setOutput('');
    try {
      const r = await titan.api.call('/api/message', { method: 'POST', body: { content: `Write ${language} code for this spec:\n\n${spec}\n\nReturn ONLY the code, no markdown fences, no explanation. The code must run as-is.` } });
      const text = (r?.content || r?.text || '').replace(/^```\w*\n?/gm, '').replace(/```$/gm, '').trim();
      setCode(text);
    } catch (e) { setOutput('Error: ' + (e?.message||e)); }
    setBusy(false);
  };
  const exec = async () => {
    setBusy(true); setOutput('');
    try {
      const r = await titan.api.call('/api/skills/execute_code', { method: 'POST', body: { code, language } });
      setOutput(r?.stdout || r?.output || JSON.stringify(r, null, 2));
      if (r?.stderr) setOutput(o => o + '\n--- stderr ---\n' + r.stderr);
    } catch (e) { setOutput('Error: ' + (e?.message||e)); }
    setBusy(false);
  };
  return (
    <div style={{padding:12,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column',gap:8}}>
      <div style={{display:'flex',gap:6,alignItems:'center'}}>
        <div style={{fontSize:14,fontWeight:600,flex:1}}>👨‍💻 Coder</div>
        <select value={language} onChange={e=>setLanguage(e.target.value)} style={{padding:'4px 8px',border:'1px solid #ccc',borderRadius:6,fontSize:12}}>
          <option value="python">Python</option><option value="javascript">JS</option><option value="typescript">TS</option><option value="bash">Bash</option>
        </select>
      </div>
      <textarea value={spec} onChange={e=>setSpec(e.target.value)} placeholder="Describe what to build…" rows={2} style={{padding:'8px',border:'1px solid #ccc',borderRadius:6,fontSize:12,resize:'vertical',fontFamily:'inherit'}}/>
      <div style={{display:'flex',gap:6}}>
        <button onClick={draft} disabled={busy} style={{flex:1,padding:'6px',border:'none',borderRadius:6,background:'#007AFF',color:'#fff',cursor:busy?'wait':'pointer',fontWeight:600,fontSize:12}}>{busy?'…':'✨ Draft'}</button>
        <button onClick={exec} disabled={busy||!code} style={{flex:1,padding:'6px',border:'none',borderRadius:6,background:'#34C759',color:'#fff',cursor:busy?'wait':'pointer',fontWeight:600,fontSize:12,opacity:code?1:0.5}}>▶ Run</button>
      </div>
      <textarea value={code} onChange={e=>setCode(e.target.value)} placeholder="Code appears here. Edit before running." style={{flex:1,padding:'10px',border:'1px solid #ccc',borderRadius:6,fontSize:12,fontFamily:'ui-monospace,SFMono-Regular,Menlo,monospace',resize:'none',minHeight:100}}/>
      {output && <pre style={{margin:0,padding:10,background:'#1e1e1e',color:'#d4d4d4',borderRadius:6,fontSize:11,maxHeight:200,overflow:'auto',whiteSpace:'pre-wrap'}}>{output}</pre>}
    </div>
  );
}
render(<CoderAgent/>);
